module sync_reset_register(clk, reset, d, q);

    input  clk;  
    input  reset;  
    input  [7:0] d;  
    output  [7:0] q;  
    reg    [7:0] q; 
    initial q = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
          begin
            if (reset) 
                q <= 0;
            else
                q <= d;
          end  

endmodule
